import random
from datetime import datetime, timedelta
from typing import List, Dict


def _spread_dates(n: int, days_back: int = 180) -> List[datetime]:
    now = datetime.now()
    return sorted(
        now - timedelta(days=random.randint(0, days_back), hours=random.randint(0, 23))
        for _ in range(n)
    )


