_CATEGORY_MAP = {
    "oral care": "oral care", "toothpaste": "oral care", "fluoride": "oral care",
    "neem": "oral care", "dental": "oral care", "whitening": "oral care",
    "skincare": "skincare", "moisturizer": "skincare", "serum": "skincare",
    "sunscreen": "skincare", "retinol": "skincare", "spf": "skincare",
    "beverage": "beverages", "drink": "beverages", "sugar": "beverages",
    "kombucha": "beverages", "energy drink": "beverages", "protein shake": "beverages",
    "wellness": "wellness", "supplement": "wellness", "vitamin": "wellness",
    "probiotic": "wellness", "adaptogen": "wellness", "ashwagandha": "wellness",
    "haircare": "haircare", "hair": "haircare", "shampoo": "haircare",
    "scalp": "haircare", "conditioner": "haircare",
}


def get_conversations(classification: dict) -> List[Dict]:
    topic = classification.get("topic", "").lower()
    category = classification.get("category", "").lower()
    keywords = [k.lower() for k in classification.get("keywords", [])]

    all_text = " ".join([topic, category] + keywords)
    matched_key = None

    for map_key, data_key in _CATEGORY_MAP.items():
        if map_key in all_text:
            matched_key = data_key
            break

    if not matched_key:
        matched_key = "oral care"

    raw = _RAW[matched_key]
    dates = _spread_dates(len(raw))

    conversations = []
    for i, item in enumerate(raw):
        conversations.append({
            "text": item["text"],
            "source": item["source"],
            "engagement": item["engagement"],
            "country": item["country"],
            "timestamp": dates[i],
        })

    return conversations
